#include <bits/stdc++.h>
using namespace std;
long long f[15][127][127][127],mi[15][127];

inline int mod(int a,int b){
    return (a%b+b)%b;
}

long long fac(long long r){
    int a[15],n;
    for(n=0;r;r/=10)
        a[++n]=r%10;
    long long ans=0;
    for(int sum=1;sum<127;sum++){
        int t=0,q=0;
        for(int i=n;i;i--){
            for(int p=0;p<a[i];p++){
                if(t+p>sum)
                    break;
                ans+=f[i-1][sum-t-p][sum][mod(0-q-p*mi[i-1][sum],sum)];
            }
            t+=a[i];
            q=(q+a[i]*mi[i-1][sum])%sum;
        }
        if(t==sum && q==0)
            ans++;
    }
    return ans;
}

int main(){
    for(int k=1;k<127;k++){
        mi[0][k]=1%k;
        for(int i=1;i<=14;i++)
            mi[i][k]=mi[i-1][k]*10%k;
        f[0][0][k][0]=1;
        for(int i=1;i<=14;i++)
            for(int j=0;j<127;j++)
                for(int l=0;l<k;l++)
                    for(int p=0;p<=9;p++){
                        if(j-p<0)
                            break;
                        f[i][j][k][l]+=f[i-1][j-p][k][mod(l-p*mi[i-1][k],k)];
                    }
    }
    long long n;
    scanf("%lld",&n);
    printf("%lld",fac(n));
    return 0;
}
